import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

export default function FigmaLogin() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const { login } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        const success = await login(email, password);
        if (success) navigate('/');
    };

    return (
        <div style={{ 
            minHeight: '100vh', 
            background: '#0F0F0F',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
        }}>
            <div style={{
                background: '#1A1A1A',
                padding: '40px',
                borderRadius: '24px',
                width: '100%',
                maxWidth: '400px'
            }}>
                <div className="logo-174" style={{ position: 'static', marginBottom: '30px', textAlign: 'center' }}>
                    <div className="rectangle-982-175" style={{ margin: '0 auto' }}></div>
                </div>
                <h2 style={{ color: 'white', marginBottom: '24px', textAlign: 'center' }}>Вход</h2>
                <form onSubmit={handleSubmit}>
                    <input 
                        type="email" 
                        placeholder="Email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        style={{
                            width: '100%',
                            padding: '12px',
                            marginBottom: '16px',
                            background: '#2A2A2A',
                            border: 'none',
                            borderRadius: '12px',
                            color: 'white'
                        }}
                        required
                    />
                    <input 
                        type="password" 
                        placeholder="Пароль"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        style={{
                            width: '100%',
                            padding: '12px',
                            marginBottom: '24px',
                            background: '#2A2A2A',
                            border: 'none',
                            borderRadius: '12px',
                            color: 'white'
                        }}
                        required
                    />
                    <button type="submit" className="text-88" style={{ width: '100%' }}>
                        Войти
                    </button>
                </form>
                <p style={{ textAlign: 'center', marginTop: '20px', color: '#999' }}>
                    Нет аккаунта? <Link to="/register" style={{ color: '#8B5CF6' }}>Регистрация</Link>
                </p>
            </div>
        </div>
    );
}
